{
  "sentences": [
    {
      "text": "你正在做什麼？",
      "pinyin": "Nǐ zhèngzài zuò shénme?",
      "pinyin_numeric": "ni3 zheng4zai4 zuo4 shen2me0",
      "translation_en": "What are you doing right now?",
      "translation_ko": "지금 무엇을 하고 계세요?"
    },
    {
      "text": "我正在看書。",
      "pinyin": "Wǒ zhèngzài kàn shū.",
      "pinyin_numeric": "wo3 zheng4zai4 kan4 shu1",
      "translation_en": "I am reading a book.",
      "translation_ko": "저는 책을 보고 있어요."
    },
    {
      "text": "他正在上網。",
      "pinyin": "Tā zhèngzài shàngwǎng.",
      "pinyin_numeric": "ta1 zheng4zai4 shang4wang3",
      "translation_en": "He is browsing the internet.",
      "translation_ko": "그는 인터넷을 하고 있어요."
    },
    {
      "text": "她正在滑手機。",
      "pinyin": "Tā zhèngzài huá shǒujī.",
      "pinyin_numeric": "ta1 zheng4zai4 hua2 shou3ji1",
      "translation_en": "She is scrolling on her phone.",
      "translation_ko": "그녀는 핸드폰을 보고 있어요."
    },
    {
      "text": "我們正在開會。",
      "pinyin": "Wǒmen zhèngzài kāihuì.",
      "pinyin_numeric": "wo3men0 zheng4zai4 kai1hui4",
      "translation_en": "We are having a meeting.",
      "translation_ko": "우리는 회의 중이에요."
    },
    {
      "text": "你正在寫功課嗎？",
      "pinyin": "Nǐ zhèngzài xiě gōngkè ma?",
      "pinyin_numeric": "ni3 zheng4zai4 xie3 gong1ke4 ma0",
      "translation_en": "Are you doing your homework right now?",
      "translation_ko": "지금 숙제를 하고 있나요?"
    },
    {
      "text": "他正在講電話。",
      "pinyin": "Tā zhèngzài jiǎng diànhuà.",
      "pinyin_numeric": "ta1 zheng4zai4 jiang3 dian4hua4",
      "translation_en": "He is talking on the phone.",
      "translation_ko": "그는 전화 통화 중이에요."
    },
    {
      "text": "我媽媽正在煮飯。",
      "pinyin": "Wǒ māma zhèngzài zhǔ fàn.",
      "pinyin_numeric": "wo3 ma1ma0 zheng4zai4 zhu3 fan4",
      "translation_en": "My mom is cooking rice.",
      "translation_ko": "우리 엄마는 밥을 짓고 있어요."
    },
    {
      "text": "你正在忙嗎？",
      "pinyin": "Nǐ zhèngzài máng ma?",
      "pinyin_numeric": "ni3 zheng4zai4 mang2 ma0",
      "translation_en": "Are you busy right now?",
      "translation_ko": "지금 바쁘세요?"
    },
    {
      "text": "我哥哥正在看電視。",
      "pinyin": "Wǒ gēge zhèngzài kàn diànshì.",
      "pinyin_numeric": "wo3 ge1ge0 zheng4zai4 kan4 dian4shi4",
      "translation_en": "My older brother is watching TV.",
      "translation_ko": "우리 오빠는 텔레비전을 보고 있어요."
    }
  ]
}
